import java.io.*;

public class XSSSecureCode {
    public static void main(String[] args) {
        String userInput = "<script>alert('XSS Attack!');</script>";

        // Encode user input to prevent XSS
        String encodedInput = encodeForHtml(userInput);

        // Output the sanitized input
        System.out.println("<div>" + encodedInput + "</div>");
    }

    // Function to encode user input for HTML output
    private static String encodeForHtml(String input) {
        return input.replaceAll("&", "&amp;")
                    .replaceAll("<", "&lt;")
                    .replaceAll(">", "&gt;")
                    .replaceAll("\"", "&quot;")
                    .replaceAll("'", "&#39;");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
